using ArchStudy.Cqrs.Commands;
using ArchStudy.Cqrs.Infrastructure;
using ArchStudy.Cqrs.Presentation;
using ArchStudy.Cqrs.Queries;
using ArchStudy.Shared.Dtos;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Cqrs;

public static class CqrsModule
{
    private const string ConnectionString = "Data Source=archstudy-cqrs.db";

    public static IServiceCollection AddCqrsModule(this IServiceCollection services)
    {
        services.AddDbContext<CqrsWriteDbContext>(o => o.UseSqlite(ConnectionString));
        services.AddDbContext<CqrsReadDbContext>(o => o.UseSqlite(ConnectionString));

        services.AddScoped<ICommandHandler<CreateAccountCommand, AccountResponse>, CreateAccountHandler>();
        services.AddScoped<ICommandHandler<DepositCommand, AccountResponse>, DepositHandler>();
        services.AddScoped<ICommandHandler<WithdrawCommand, AccountResponse>, WithdrawHandler>();
        services.AddScoped<ICommandHandler<TransferCommand>, TransferHandler>();

        services.AddScoped<IQueryHandler<GetAccountQuery, AccountResponse?>, GetAccountHandler>();
        services.AddScoped<IQueryHandler<GetStatementQuery, IReadOnlyList<TransactionResponse>>, GetStatementHandler>();
        return services;
    }

    public static IEndpointRouteBuilder MapCqrsModule(this IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/cqrs").WithTags("CQRS");
        CqrsEndpoints.Map(group);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<CqrsWriteDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

using ArchStudy.Shared.Dtos;

namespace ArchStudy.Cqrs.Domain;

public class AccountWriteModel
{
    public Guid Id { get; set; }
    public string Owner { get; set; } = string.Empty;
    public decimal Balance { get; set; }
    public DateTime CreatedAt { get; set; }
}

public class TransactionWriteModel
{
    public Guid Id { get; set; }
    public Guid AccountId { get; set; }
    public TransactionType Type { get; set; }
    public decimal Amount { get; set; }
    public DateTime Timestamp { get; set; }
    public Guid? RelatedAccountId { get; set; }
}

using ArchStudy.Cqrs.Domain;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Cqrs.Infrastructure;

public class CqrsWriteDbContext(DbContextOptions<CqrsWriteDbContext> options) : DbContext(options)
{
    public DbSet<AccountWriteModel> Accounts => Set<AccountWriteModel>();
    public DbSet<TransactionWriteModel> Transactions => Set<TransactionWriteModel>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<AccountWriteModel>(b =>
        {
            b.ToTable("Accounts");
            b.HasKey(a => a.Id);
        });
        modelBuilder.Entity<TransactionWriteModel>(b =>
        {
            b.ToTable("Transactions");
            b.HasKey(t => t.Id);
        });
    }
}

public class CqrsReadDbContext(DbContextOptions<CqrsReadDbContext> options) : DbContext(options)
{
    public DbSet<AccountWriteModel> Accounts => Set<AccountWriteModel>();
    public DbSet<TransactionWriteModel> Transactions => Set<TransactionWriteModel>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<AccountWriteModel>(b =>
        {
            b.ToTable("Accounts");
            b.HasKey(a => a.Id);
        });
        modelBuilder.Entity<TransactionWriteModel>(b =>
        {
            b.ToTable("Transactions");
            b.HasKey(t => t.Id);
        });
    }
}

using ArchStudy.Cqrs.Commands;
using ArchStudy.Cqrs.Queries;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Cqrs.Presentation;

public static class CqrsEndpoints
{
    public static void Map(RouteGroupBuilder group)
    {
        group.MapPost("/accounts", async Task<IResult> (
            CreateAccountRequest req,
            ICommandHandler<CreateAccountCommand, AccountResponse> handler,
            CancellationToken ct) =>
        {
            var account = await handler.Handle(new CreateAccountCommand(req.Owner), ct);
            return Results.Created($"/cqrs/accounts/{account.Id}", account);
        });

        group.MapGet("/accounts/{id:guid}", async Task<IResult> (
            Guid id,
            IQueryHandler<GetAccountQuery, AccountResponse?> handler,
            CancellationToken ct) =>
        {
            var account = await handler.Handle(new GetAccountQuery(id), ct);
            return account is null ? Results.NotFound() : Results.Ok(account);
        });

        group.MapGet("/accounts/{id:guid}/transactions", async Task<IResult> (
            Guid id,
            IQueryHandler<GetStatementQuery, IReadOnlyList<TransactionResponse>> handler,
            CancellationToken ct) =>
            Results.Ok(await handler.Handle(new GetStatementQuery(id), ct)));

        group.MapPost("/accounts/{id:guid}/deposits", async Task<IResult> (
            Guid id,
            DepositRequest req,
            ICommandHandler<DepositCommand, AccountResponse> handler,
            CancellationToken ct) =>
            Results.Ok(await handler.Handle(new DepositCommand(id, req.Amount), ct)));

        group.MapPost("/accounts/{id:guid}/withdrawals", async Task<IResult> (
            Guid id,
            WithdrawalRequest req,
            ICommandHandler<WithdrawCommand, AccountResponse> handler,
            CancellationToken ct) =>
            Results.Ok(await handler.Handle(new WithdrawCommand(id, req.Amount), ct)));

        group.MapPost("/transfers", async Task<IResult> (
            TransferRequest req,
            ICommandHandler<TransferCommand> handler,
            CancellationToken ct) =>
        {
            await handler.Handle(new TransferCommand(req.FromAccountId, req.ToAccountId, req.Amount), ct);
            return Results.NoContent();
        });
    }
}

using ArchStudy.Cqrs.Infrastructure;
using ArchStudy.Shared.Dtos;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Cqrs.Queries;

public sealed record GetAccountQuery(Guid Id) : IQuery<AccountResponse?>;

public sealed class GetAccountHandler(CqrsReadDbContext db) : IQueryHandler<GetAccountQuery, AccountResponse?>
{
    public async ValueTask<AccountResponse?> Handle(GetAccountQuery query, CancellationToken ct)
    {
        var account = await db.Accounts
            .AsNoTracking()
            .Where(a => a.Id == query.Id)
            .Select(a => new AccountResponse(a.Id, a.Owner, a.Balance, a.CreatedAt))
            .FirstOrDefaultAsync(ct);
        return account;
    }
}

using ArchStudy.Cqrs.Infrastructure;
using ArchStudy.Shared.Dtos;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Cqrs.Queries;

public sealed record GetStatementQuery(Guid AccountId) : IQuery<IReadOnlyList<TransactionResponse>>;

public sealed class GetStatementHandler(CqrsReadDbContext db) : IQueryHandler<GetStatementQuery, IReadOnlyList<TransactionResponse>>
{
    public async ValueTask<IReadOnlyList<TransactionResponse>> Handle(GetStatementQuery query, CancellationToken ct)
    {
        var list = await db.Transactions
            .AsNoTracking()
            .Where(t => t.AccountId == query.AccountId)
            .OrderByDescending(t => t.Timestamp)
            .Select(t => new TransactionResponse(t.Id, t.AccountId, t.Type, t.Amount, t.Timestamp, t.RelatedAccountId))
            .ToListAsync(ct);
        return list;
    }
}
